/**
 * 🧬 OpenGenetics — Genetic SDK (Vanilla JavaScript)
 * genetics.min.js
 * 
 * Single-file SDK for connecting any frontend to the OpenGenetics API.
 * Usage: <script src="genetics.min.js"></script>
 * 
 * @version 1.0.0
 */
(function (global) {
    'use strict';

    const Genetics = {
        // ─── Configuration ───────────────────────────
        _config: {
            baseUrl: '/open-genetics/public/api',
            token: null,
            locale: 'en',
            theme: 'system',
            translations: {},
        },

        /**
         * Initialize the SDK.
         * @param {Object} options - { baseUrl, locale, theme }
         */
        init(options = {}) {
            if (options.baseUrl) this._config.baseUrl = options.baseUrl.replace(/\/$/, '');
            if (options.locale) this._config.locale = options.locale;
            if (options.theme)  this.setTheme(options.theme);

            // Restore token from localStorage
            const savedToken = localStorage.getItem('og_token');
            if (savedToken) this._config.token = savedToken;

            // Restore locale
            const savedLocale = localStorage.getItem('og_locale');
            if (savedLocale) this._config.locale = savedLocale;

            // Restore theme
            const savedTheme = localStorage.getItem('og_theme');
            if (savedTheme) this.setTheme(savedTheme);

            // Load translations
            this.loadTranslations();

            console.log('🧬 OpenGenetics SDK initialized');
            return this;
        },

        // ─── Auth ────────────────────────────────────

        /**
         * Login and store JWT token.
         * @param {string} email
         * @param {string} password
         * @returns {Promise<Object>}
         */
        async login(email, password) {
            const res = await this.fetch('auth/login', {
                method: 'POST',
                body: { email, password },
            });

            if (res.success && res.data.token) {
                this._config.token = res.data.token;
                localStorage.setItem('og_token', res.data.token);
                localStorage.setItem('og_user', JSON.stringify(res.data.user));
            }

            return res;
        },

        /**
         * Register a new user.
         * @param {string} email
         * @param {string} password
         * @param {number} roleId
         * @returns {Promise<Object>}
         */
        async register(email, password, roleId = 3) {
            const res = await this.fetch('auth/register', {
                method: 'POST',
                body: { email, password, role_id: roleId },
            });

            if (res.success && res.data.token) {
                this._config.token = res.data.token;
                localStorage.setItem('og_token', res.data.token);
                localStorage.setItem('og_user', JSON.stringify(res.data.user));
            }

            return res;
        },

        /**
         * Forgot password — request reset token.
         * @param {string} email
         * @returns {Promise<Object>}
         */
        async forgotPassword(email) {
            return this.fetch('auth/forgot-password', {
                method: 'POST',
                body: { email },
            });
        },

        /**
         * Reset password using token.
         * @param {string} token
         * @param {string} password
         * @returns {Promise<Object>}
         */
        async resetPassword(token, password) {
            return this.fetch('auth/reset-password', {
                method: 'POST',
                body: { token, password },
            });
        },

        /**
         * Get current user profile.
         * @returns {Promise<Object>}
         */
        async getProfile() {
            return this.fetch('auth/profile');
        },

        /**
         * Logout — clear token and user data.
         */
        logout() {
            this._config.token = null;
            localStorage.removeItem('og_token');
            localStorage.removeItem('og_user');
        },

        /**
         * Check if user is authenticated.
         * @returns {boolean}
         */
        isAuthenticated() {
            return !!this._config.token;
        },

        /**
         * Get stored user data.
         * @returns {Object|null}
         */
        getUser() {
            const data = localStorage.getItem('og_user');
            return data ? JSON.parse(data) : null;
        },

        // ─── API Fetch ───────────────────────────────

        /**
         * Generic API fetch method.
         * @param {string} endpoint - API endpoint (without /api/ prefix)
         * @param {Object} options - { method, body, headers }
         * @returns {Promise<Object>}
         */
        async fetch(endpoint, options = {}) {
            const url = `${this._config.baseUrl}/${endpoint.replace(/^\//, '')}`;

            const headers = {
                'Content-Type': 'application/json',
                'X-Locale': this._config.locale,
                ...(options.headers || {}),
            };

            if (this._config.token) {
                headers['Authorization'] = `Bearer ${this._config.token}`;
            }

            const fetchOptions = {
                method: options.method || 'GET',
                headers,
            };

            if (options.body && fetchOptions.method !== 'GET') {
                fetchOptions.body = JSON.stringify(options.body);
            }

            try {
                const response = await window.fetch(url, fetchOptions);
                const data = await response.json();

                // Auto-logout on 401
                if (response.status === 401) {
                    this.logout();
                }

                return data;
            } catch (error) {
                console.error('🧬 Genetics.fetch error:', error);
                return { success: false, message: error.message };
            }
        },

        // ─── i18n ────────────────────────────────────

        /**
         * Load translations for the current locale.
         */
        async loadTranslations() {
            try {
                const res = await this.fetch(`i18n?lang=${this._config.locale}`);
                if (res.success) {
                    this._config.translations = res.data.translations;
                }
            } catch (e) {
                console.warn('🧬 Failed to load translations:', e);
            }
        },

        /**
         * Translate a key (dot notation).
         * @param {string} key - e.g. "auth.login"
         * @param {Object} params - Replacement params
         * @returns {string}
         */
        t(key, params = {}) {
            let value = this._config.translations;
            const parts = key.split('.');

            for (const part of parts) {
                if (value && typeof value === 'object' && part in value) {
                    value = value[part];
                } else {
                    return key; // fallback to key
                }
            }

            if (typeof value !== 'string') return key;

            // Replace :param placeholders
            Object.keys(params).forEach(k => {
                value = value.replace(`:${k}`, params[k]);
            });

            return value;
        },

        /**
         * Set locale and reload translations.
         * @param {string} locale - 'en' or 'th'
         */
        async setLocale(locale) {
            this._config.locale = locale;
            localStorage.setItem('og_locale', locale);
            await this.loadTranslations();

            // Dispatch event for reactive UIs
            document.dispatchEvent(new CustomEvent('og:locale-changed', {
                detail: { locale, translations: this._config.translations }
            }));
        },

        /**
         * Get current locale.
         * @returns {string}
         */
        getLocale() {
            return this._config.locale;
        },

        // ─── Theme ───────────────────────────────────

        /**
         * Set theme mode and apply CSS variables.
         * @param {string} mode - 'light', 'dark', or 'system'
         */
        setTheme(mode) {
            this._config.theme = mode;
            localStorage.setItem('og_theme', mode);

            let resolved = mode;
            if (mode === 'system') {
                resolved = window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
            }

            document.documentElement.setAttribute('data-theme', resolved);
            document.documentElement.classList.toggle('dark', resolved === 'dark');

            // Dispatch event
            document.dispatchEvent(new CustomEvent('og:theme-changed', {
                detail: { mode, resolved }
            }));
        },

        /**
         * Get current theme mode.
         * @returns {string}
         */
        getTheme() {
            return this._config.theme;
        },

        // ─── Dashboard ──────────────────────────────

        /**
         * Get dashboard statistics.
         * @returns {Promise<Object>}
         */
        async getDashboard() {
            return this.fetch('dashboard');
        },

        /**
         * Get users list.
         * @param {Object} params - { page, per_page, search }
         * @returns {Promise<Object>}
         */
        async getUsers(params = {}) {
            const query = new URLSearchParams(params).toString();
            return this.fetch(`users?${query}`);
        },

        /**
         * Get audit logs.
         * @param {Object} params - { page, per_page, action, entity, user_id }
         * @returns {Promise<Object>}
         */
        async getAuditLogs(params = {}) {
            const query = new URLSearchParams(params).toString();
            return this.fetch(`audit-logs?${query}`);
        },
    };

    // Expose globally
    global.Genetics = Genetics;

})(typeof window !== 'undefined' ? window : globalThis);
